add_action('wpforms_process_complete', function($fields, $entry, $form_data) {

    $user_id = get_current_user_id();
    if (!$user_id) return;

    $vehicle_id_input = $fields[4]['value'] ?? '';
    if (!$vehicle_id_input) return;

    $query = new WP_Query([
        'post_type' => 'vehicle',
        'meta_query' => [
            [
                'key' => 'vehicle_id',
                'value' => $vehicle_id_input,
                'compare' => '='
            ]
        ]
    ]);

    if ($query->have_posts()) {
        $query->the_post();
        $post_id = get_the_ID();

        $data = [
    'user_id' => $user_id,
    'email'   => wp_get_current_user()->user_email,
    'name'    => wp_get_current_user()->display_name,
    'brand'   => get_field('marka_prevozno_sredstvo', $post_id),
    'reg'     => get_field('reg_nomer', $post_id),
    'id'      => $vehicle_id_input
];

add_post_meta($post_id, 'pending_user_' . $user_id, $data);

    }

    wp_reset_postdata();

}, 10, 3);


