add_shortcode('my_vehicles', function () {

    if (!is_user_logged_in()) {
        return '<p>Трябва да сте влезли.</p>';
    }

    $user_id = get_current_user_id();

    $query = new WP_Query([
        'post_type' => 'vehicle',
        'meta_query' => [
            [
                'key' => 'assigned_users',
                'value' => $user_id,
                'compare' => 'LIKE'
            ]
        ]
    ]);

    ob_start();

    echo "<div class='vehicle-grid'>";

    if ($query->have_posts()) {
        while ($query->have_posts()) {
            $query->the_post();

            echo "<div class='vehicle-card'>";
            echo "<h3>" . get_field('marka_prevozno_sredstvo') . "</h3>";
            echo "<p><strong>Рег. номер:</strong> " . get_field('reg_nomer') . "</p>";
            echo "</div>";
        }
    } else {
        echo "<p>Нямате добавени автомобили.</p>";
    }

    echo "</div>";

    wp_reset_postdata();

    return ob_get_clean();
});


