add_filter('wp_nav_menu_items', function ($items, $args) {

    // ако НЕ е логнат
    if (!is_user_logged_in()) {
        $items .= '<li><a href="/login">Вход</a></li>';
        return $items;
    }

    $user_id = get_current_user_id();

    $vehicles = new WP_Query([
        'post_type' => 'vehicle',
        'posts_per_page' => -1
    ]);

    $filtered_vehicles = [];

    if ($vehicles->have_posts()) {
        while ($vehicles->have_posts()) {
            $vehicles->the_post();

            $assigned = get_field('assigned_users');

            if ($assigned && is_array($assigned)) {
                foreach ($assigned as $user) {

                    if (
                        (is_object($user) && $user->ID == $user_id) ||
                        (is_numeric($user) && $user == $user_id)
                    ) {
                        $filtered_vehicles[] = get_the_ID();
                    }
                }
            }
        }
    }

    wp_reset_postdata();

    // =========================
    // 👤 ПРОФИЛ
    // =========================
    $items .= '<li class="menu-item menu-item-has-children">';
    $items .= '<a href="#">Профил</a>';
    $items .= '<ul class="sub-menu">';

    $items .= '<li><a href="/account">Акаунт</a></li>';
    $items .= '<li><a href="/add-vehicle">Добави МПС</a></li>';

    // =========================
    // 🚗 МОИТЕ МПС
    // =========================
    if (!empty($filtered_vehicles)) {

        $items .= '<li class="menu-item menu-item-has-children">';
        $items .= '<a href="#">Моите МПС</a>';
        $items .= '<ul class="sub-menu">';

        foreach ($filtered_vehicles as $vehicle_id_post) {

            $brand = get_field('marka_prevozno_sredstvo', $vehicle_id_post);
            $reg   = get_field('reg_nomer', $vehicle_id_post);
            $vehicle_id = get_field('vehicle_id', $vehicle_id_post);

            $title = trim($reg . ' ' . $brand);

            if (empty($title)) {
                $title = 'МПС #' . $vehicle_id;
            }

            $items .= '<li>
                <a href="/moeto-prevozno-sredstvo/?vehicle_id=' . urlencode($vehicle_id) . '">
                    🚗 ' . esc_html($title) . '
                </a>
            </li>';
        }

        $items .= '</ul></li>';
    }

    // =========================
    // 🚪 ИЗХОД
    // =========================
    $items .= '<li><a href="' . wp_logout_url(home_url()) . '">Изход</a></li>';

    $items .= '</ul></li>';

    return $items;

}, 10, 2);


